int fib(int n) {
    if (n < 2) return n;
    int x = cilk_spawn fib(n - 1);  // spawn: Elternthread in Deque, weiter mit fib(n-1)
    int y = fib(n - 2);              // läuft inline
    cilk_sync;                       // stall: warte auf gespawnten Thread
    return x + y;
}
